   import * as fs from 'fs';

   const input = fs.readFileSync(0, "utf8").trim();
   let pos = 0;

   function skipSpaces() {
       while (pos < input.length && input[pos] === ' ') pos++;
   }

   function peek() {
       skipSpaces();
       return pos < input.length ? input[pos] : '';
   }

   function consume() {
       skipSpaces();
       if (pos >= input.length) throw new Error("Unexpected end of input");
       return input[pos++];
   }

   function parseNumber() {
       skipSpaces();
       let numStr = '';
       if (pos < input.length && (input[pos] === '+' || input[pos] === '-')) {
           // Actually, unary +/- are handled in parseUnary, so numbers here are just digits.
           // But wait, the grammar says Unary handles +/-, so Primary should only parse digits or parenthesized expressions.
           // So parseNumber only consumes digits.
       }
       while (pos < input.length && input[pos] >= '0' && input[pos] <= '9') {
           numStr += input[pos++];
       }
       if (numStr === '') throw new Error("Expected number");
       return parseInt(numStr, 10);
   }

   function parsePrimary() {
       skipSpaces();
       const ch = peek();
       if (ch === '(') {
           consume(); // consume '('
           const val = parseExpression();
           skipSpaces();
           if (peek() !== ')') throw new Error("Expected ')'");
           consume(); // consume ')'
           return val;
       } else {
           return parseNumber();
       }
   }

   function parseUnary() {
       skipSpaces();
       if (peek() === '+' || peek() === '-') {
           const op = consume();
           const val = parseUnary();
           return op === '-' ? -val : val;
       }
       return parsePrimary();
   }

   function parseTerm() {
       let left = parseUnary();
       while (true) {
           skipSpaces();
           const ch = peek();
           if (ch === '*' || ch === '/') {
               consume();
               const right = parseUnary();
               if (ch === '*') {
                   left = left * right;
               } else {
                   left = Math.trunc(left / right);
               }
           } else {
               break;
           }
       }
       return left;
   }

   function parseExpression() {
       let left = parseTerm();
       while (true) {
           skipSpaces();
           const ch = peek();
           if (ch === '+' || ch === '-') {
               consume();
               const right = parseTerm();
               if (ch === '+') {
                   left = left + right;
               } else {
                   left = left - right;
               }
           } else {
               break;
           }
       }
       return left;
   }

   const result = parseExpression();
   console.log(result);
   ```

